ALTER TABLE `telemetry_logs` ADD COLUMN `event_urn` String MATERIALIZED toString(attributes.gram.event.urn) COMMENT 'Canonical event identity in the form urn:gram:telemetry:event:<origin>:<kind>:<type> where origin is the observation channel (provider_otel | provider_api | agent_hook | gram_gateway | gram_runtime | gram_worker | unknown), kind is the signal shape (log | metric) and type is the producer event type. Stamped by telemetry.Logger. Empty on rows written before the column existed (materialized from attributes.gram.event.urn).';
ALTER TABLE `telemetry_logs` ADD INDEX `idx_telemetry_logs_mat_event_urn` ((event_urn)) TYPE set(0) GRANULARITY 4;
